#!/usr/bin/env python3
"""Before `git commit`, run `pnpm lint`; block the commit if lint fails.

CLAUDE.md states: run lint with `pnpm lint` before committing. This enforces it.
"""
import json, re, subprocess, sys

GIT_COMMIT = re.compile(r"\bgit\s+commit\b")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not GIT_COMMIT.search(cmd):
        return 0
    try:
        r = subprocess.run(
            ["pnpm", "lint"], capture_output=True, text=True, timeout=60
        )
    except Exception:
        return 0  # if lint can't run at all, don't block the commit
    if r.returncode != 0:
        tail = (r.stdout + r.stderr).strip().splitlines()[-20:]
        print(
            "BLOCKING: `pnpm lint` failed — CLAUDE.md requires lint to pass before committing.",
            file=sys.stderr,
        )
        for line in tail:
            print(f"  {line}", file=sys.stderr)
        print("Fix the lint errors above, then re-run the commit.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

import json, os, re, sys

# Matches a .env-family filename token: .env, .env.local, .env.production, etc.
ENV_FILE = r"\.env(?:\.[\w-]+)*"
ENV_TOKEN = re.compile(r"(?:^|[\s'\"=/<>|&;(])" + ENV_FILE + r"\b")
# Shell utilities that read/print file contents.
READ_CMD = re.compile(
    r"\b(?:cat|tac|less|more|head|tail|grep|egrep|fgrep|rg|ag|ack|awk|sed|"
    r"nl|xxd|od|hexdump|strings|cut|sort|uniq|bat|view|vi|vim|nano|emacs|"
    r"printenv|source)\b"
)
REDIR_ENV = re.compile(r"<\s*\S*" + ENV_FILE + r"\b")

MSG = (
    "BLOCKED: this project forbids reading .env files. .env.local holds live "
    "secrets. Get any needed config value from the user or from documented "
    "non-secret sources instead. Do not retry this read."
)


def is_env_path(path):
    base = os.path.basename(path.strip().strip("'\""))
    return base == ".env" or base.startswith(".env.")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool == "Read":
        path = inp.get("file_path", "") or ""
        if path and is_env_path(path):
            print(MSG, file=sys.stderr)
            return 2
        return 0
    if tool == "Bash":
        cmd = inp.get("command", "") or ""
        if ENV_TOKEN.search(cmd) and (READ_CMD.search(cmd) or REDIR_ENV.search(cmd)):
            print(MSG, file=sys.stderr)
            return 2
        return 0
    return 0


if __name__ == "__main__":
    sys.exit(main())

import json, re, sys

WRITE_SQL = re.compile(
    r"\b(INSERT|UPDATE|DELETE|CREATE|ALTER|DROP|REPLACE|PRAGMA|VACUUM)\b", re.I
)
REDIRECT_DB = re.compile(r">>?\s*[^\s|;&]*dev\.db")
FILEOP_DB = re.compile(r"\b(cp|mv|rm|dd|tee|truncate)\b[^\n]*dev\.db")


def bash_writes_db(cmd):
    if "dev.db" not in cmd:
        return False
    if REDIRECT_DB.search(cmd):
        return True
    if FILEOP_DB.search(cmd):
        return True
    if "sqlite3" in cmd and WRITE_SQL.search(cmd):
        return True
    return False


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    hit = False
    if tool == "Bash":
        hit = bash_writes_db(inp.get("command", "") or "")
    elif tool in ("Edit", "Write", "MultiEdit"):
        hit = "dev.db" in (inp.get("file_path", "") or "")

    if hit:
        print(
            "BLOCKED: direct writes to prisma/dev.db are not allowed. CLAUDE.md "
            "requires all schema and data changes to go through Prisma migrations "
            "(`pnpm prisma migrate dev`). Re-run your change as a migration instead "
            "of mutating the database file directly.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
# self-improving-claude/export-rename-refs
# PostToolUse(Edit|Write|MultiEdit): when an edit changes an exported identifier
# (its name) or the string value of an exported constant, surface every
# reference across the codebase so callers can be reconciled in the same turn.
import json, re, subprocess, sys

DECL = re.compile(r'export\s+(?:default\s+)?(?:async\s+)?(?:const|let|var|function|class|interface|type|enum)\s+([A-Za-z_$][\w$]*)')
LIST = re.compile(r'export\s*\{([^}]*)\}')
STRC = re.compile(r'export\s+const\s+([A-Za-z_$][\w$]*)\s*(?::[^=]+)?=\s*[\'"`]([^\'"`]+)[\'"`]')
EXTS = ('.ts', '.tsx', '.js', '.jsx', '.mjs', '.cjs')

def names(t):
    s = set(m.group(1) for m in DECL.finditer(t))
    for m in LIST.finditer(t):
        for p in m.group(1).split(','):
            n = p.strip().split(' as ')[0].strip()
            if re.fullmatch(r'[A-Za-z_$][\w$]*', n):
                s.add(n)
    return s

def vals(t):
    return {m.group(1): m.group(2) for m in STRC.finditer(t)}

def grep(term):
    inc = [f'--include=*{e}' for e in EXTS]
    try:
        r = subprocess.run(['grep', '-rnIF', *inc, '--exclude-dir=node_modules',
            '--exclude-dir=.git', '--exclude-dir=dist', '--exclude-dir=build', term, '.'],
            capture_output=True, text=True, timeout=20)
        return [l for l in r.stdout.splitlines() if l.strip()]
    except Exception:
        return []

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get('tool_name', '')
    inp = ev.get('tool_input') or {}
    if tool not in ('Edit', 'Write', 'MultiEdit'):
        return 0
    fp = inp.get('file_path', '')
    if not fp.endswith(EXTS):
        return 0
    old = new = ''
    if tool == 'Edit':
        old, new = inp.get('old_string', ''), inp.get('new_string', '')
    elif tool == 'Write':
        new = inp.get('content', '')
    else:
        for e in inp.get('edits', []) or []:
            old += (e.get('old_string', '') or '') + '\n'
            new += (e.get('new_string', '') or '') + '\n'
    touched = names(old) | names(new)
    ov, nv = vals(old), vals(new)
    changed = [(k, ov[k], nv[k]) for k in ov if k in nv and nv[k] != ov[k]]
    if not touched and not changed:
        return 0
    report = []
    for n in sorted(touched):
        h = grep(n)
        if h:
            report.append((f"exported identifier `{n}`", h))
    for k, o, n in changed:
        h = grep(o)
        if h:
            report.append((f"old value '{o}' of `{k}` (now '{n}') still hardcoded", h))
    if not report:
        return 0
    out = ["BLOCKING: an exported identifier changed. REQUIRED FOLLOW-UP — reconcile every "
           "reference below to match the new name/value. Do not stop until each is updated. "
           "Do not ask whether to proceed."]
    for label, h in report:
        out.append(f"\n{label} — {len(h)} reference(s):")
        out += [f"  {x}" for x in h[:40]]
        if len(h) > 40:
            out.append(f"  ... and {len(h) - 40} more")
    print('\n'.join(out), file=sys.stderr)
    return 2

if __name__ == '__main__':
    sys.exit(main())

#!/usr/bin/env python3
"""Block `git push --force` to main/master — rewriting shared history is
destructive and irreversible. Regular pushes and force-pushes to feature
branches are left untouched."""
import json, shlex, sys

FORCE_FLAGS = {"-f", "--force", "--force-with-lease"}
PROTECTED = {"main", "master"}


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    try:
        toks = shlex.split(cmd)
    except Exception:
        toks = cmd.split()
    if "git" not in toks or "push" not in toks:
        return 0
    has_force = any(
        t in FORCE_FLAGS or t.startswith("--force-with-lease=") for t in toks
    )
    # branch can appear as `main`, or as a refspec like `HEAD:main` / `local:main`
    targets_protected = any(
        t in PROTECTED or t.split(":")[-1] in PROTECTED for t in toks
    )
    if has_force and targets_protected:
        print(
            "BLOCKING: force-push to main/master rewrites shared history and is "
            "not allowed. Push to a feature branch or open a PR instead. "
            "Do not retry this command.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

import json, sys, re, shlex

SUBJECT_LIMIT = 72


def extract_first_message(command):
    """Return the text of the first -m/--message value, or None if not statically parseable."""
    try:
        tokens = shlex.split(command)
    except Exception:
        return None
    i = 0
    while i < len(tokens):
        t = tokens[i]
        if t in ("-m", "--message"):
            if i + 1 < len(tokens):
                return tokens[i + 1]
            return None
        if t.startswith("--message="):
            return t[len("--message="):]
        if t.startswith("-m") and len(t) > 2:
            return t[2:]
        i += 1
    return None


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name", "") != "Bash":
        return 0
    command = (ev.get("tool_input") or {}).get("command", "")
    if "git commit" not in command:
        return 0

    msg = extract_first_message(command)
    if msg is None:
        return 0  # editor commit, heredoc, or unparseable — let git/other checks handle it
    if "$(" in msg or msg.lstrip().startswith("$"):
        return 0  # command substitution — message not statically known

    lines = msg.split("\n")
    subject = lines[0].strip()
    if not subject:
        return 0

    problems = []
    if len(subject) > SUBJECT_LIMIT:
        problems.append("subject is {} chars (keep it <= {})".format(len(subject), SUBJECT_LIMIT))
    if len(lines) > 1 and lines[1].strip() != "":
        problems.append("subject and body are run together; separate them with a blank line")
    if re.search(r"\.\s+[A-Z]", subject):
        problems.append("subject reads like prose (multiple sentences); use one short imperative phrase")

    if problems:
        print(
            "Commit message rejected — this team uses short imperative subject lines.\n"
            "Problems: " + "; ".join(problems) + ".\n"
            'Use a concise imperative subject, e.g. "Refactor auth: extract token validation".\n'
            "If you need detail, put it in a body paragraph after a blank line.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

