import json, sys, subprocess, importlib.util


def _run(args, path):
    try:
        p = subprocess.run([sys.executable, "-m", *args, path],
                           capture_output=True, text=True, timeout=20)
    except Exception:
        return None
    return p


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool not in ("Edit", "Write", "MultiEdit"):
        return 0
    path = inp.get("file_path", "")
    if not path.endswith(".py"):
        return 0

    if importlib.util.find_spec("pyflakes") is not None:
        p = _run(["pyflakes"], path)
        if p is not None and p.returncode != 0:
            findings = (p.stdout + p.stderr).strip()
            if findings:
                print("BLOCKING: pyflakes flagged static errors in " + path
                      + " (undefined names, unused imports, redefinitions):\n"
                      + findings
                      + "\nREQUIRED FOLLOW-UP: Fix each reported line now. Do not "
                      "stop or present this edit as done until pyflakes is clean.",
                      file=sys.stderr)
                return 2
        return 0

    # No pyflakes installed: fall back to a syntax-only floor (stdlib).
    p = _run(["py_compile"], path)
    if p is not None and p.returncode != 0:
        print("BLOCKING: " + path + " does not compile:\n"
              + (p.stderr or p.stdout).strip()
              + "\nREQUIRED FOLLOW-UP: Fix the syntax error now. Do not stop or "
              "present this edit as done until the file compiles.",
              file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
